import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / trivial quote ---
  it.todo("quote with empty item list returns premium 5 G (only processing fee)");

  // --- Single item base premiums (with newcomer first-insurance and fee folded in) ---
  it.todo("quote for single plain sword (newcomer, 0 years) returns premium 115 G (100 base + 10 first-insurance + 5 fee)");
  it.todo("quote for single plain amulet (newcomer) returns premium 71 G (60 base + 6 first-insurance + 5 fee)");
  it.todo("quote for single plain staff (newcomer) returns premium 93 G (80 base + 8 first-insurance + 5 fee)");
  it.todo("quote for single plain potion (newcomer) returns premium 49 G (40 base + 4 first-insurance + 5 fee)");

  // --- Component base premiums (building block of 3) ---
  it.todo("quote for 2 runes returns base premium 50 G before policy-wide modifiers (50 + 5 first-insurance + 5 fee = 60 G)");
  it.todo("quote for 3 runes applies block: base premium 60 G (60 + 6 first-insurance + 5 fee = 71 G)");
  it.todo("quote for 4 runes returns base premium 100 G — no block since block requires exactly 3 (100 + 10 first-insurance + 5 fee = 115 G)");
  it.todo("quote for 7 runes returns base premium 175 G (one block of 3 = 60 G + 4 runes × 25 G = 100 G; 175 + 18 first-insurance + 5 fee = 198 G)");

  // --- 'Alike' components clarification ---
  it.todo("quote for 2 runes + 1 moonstone returns base premium 75 G — no block since types differ (75 + 8 first-insurance + 5 fee = 88 G)");
  it.todo("quote for 3 runes + 3 moonstones returns base premium 120 G — two separate blocks (120 + 12 first-insurance + 5 fee = 137 G)");

  // --- Item-specific modifier: cursed (applies to that item only) ---
  it.todo("quote for cursed sword + plain amulet (newcomer) returns policy base 160 G + 50 G curse on the sword's 100 G base, then first-insurance and fee");

  // --- Modifier thresholds ---
  it.todo("quote for sword with enchantment exactly 5 applies high-enchantment surcharge (30 % of base premium)");
  it.todo("quote for sword with enchantment 4 does NOT apply high-enchantment surcharge");
  it.todo("quote for cursed sword with enchantment exactly 5 applies both cursed and high-enchantment surcharges");
  it.todo("quote with customer who has exactly 2 years with MHPCO applies the 20 % loyalty discount");

  // --- Integration: newcomer with a cursed sword (spec example) ---
  it.todo("integration: newcomer (0 years, first contract) cursed sword (steel, enchantment 3) returns premium 165 G");

  // --- Integration: long-standing customer's second contract (spec example) ---
  it.todo("integration: 3-years customer, 2nd quote in scenario, cursed sword (steel, enchantment 7) returns premium 160 G (loyalty + follow-up + curse + high enchantment + first-insurance per item + fee)");

  // --- Rounding in MHPCO's favor ---
  it.todo("premium calculation that yields 197.5 G is rounded UP to 198 G");
  it.todo("payout calculation that yields 350.5 G is rounded DOWN to 350 G");

  // --- Claim: standard reimbursement (no special clauses) ---
  it.todo("claim on plain steel sword (enchantment 3) with 500 G damage: payout 400 G (full minus 100 G deductible)");
  it.todo("claim on a rune (insurance value 250 G) with 200 G damage: payout 100 G (full minus 100 G deductible; runes have no enchantment/material clauses)");

  // --- Claim: high-enchantment clause ---
  it.todo("claim on steel sword, enchantment 9, damage 1000 G: payout 400 G (50 % first, then deductible)");

  // --- Claim: dragon-material clause ---
  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");

  // --- Claim: both clauses — 50 % rule wins ---
  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50 % rule wins, then deductible: 500 − 100)");
  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies, then deductible)");

  // --- Claim: deductible per damage event (multi-item single incident) ---
  it.todo("claim on sword and amulet (single dragon attack), damages [500, 300]: payout 600 G (deductible applies once per damaged item)");

  // --- Claim: cap = 2 × insurance sum ---
  it.todo("policy with sword and amulet has insurance sum 1600 G; cap is 3200 G");
  it.todo("policy with cursed sword (modifiers make premium 165 G) has cap 2000 G — modifiers do not raise the cap");
  it.todo("policy with sword and 3 runes (block) has insurance sum 1750 G — block discount affects premium only, not the insurance sum");

  // --- Claim: cap exhaustion across successive claims ---
  it.todo("sword policy (cap 2000 G), first claim 1500 G: payout 1400 G, remainingCap 600 G");
  it.todo("sword policy (cap 2000 G), second successive claim 1500 G: payout 600 G, remainingCap 0 G (reduced to remaining cap)");

  // --- Claim: multiple items of the same type ---
  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
  it.todo("claim on two swords (two separate damage entries) treats each entry as separate damage with its own deductible");
  it.todo("claim contains more entries of a given type than the policy covers: the whole claim is rejected (error)");

  // --- Edge cases / errors ---
  it.todo("quote includes an item with unknown type (e.g. broomstick): error, no results");
  it.todo("claim references an item not part of the policy (e.g. amulet damage when only a sword is insured): error");
  it.todo("claim with a negative damage amount (amount: -200): error");
});
